167	__forceinline__ __device__ int4 ldg_with_gez_pred(const int4* ptr, const int& value, const TMACacheHint& cache_hint = TMACacheHint::kEvictFirst) {
168	    int4 ret = make_int4(0, 0, 0, 0);
169	    asm volatile(
170	        "{\n\t"
171	        "  .reg .pred p;\n\t"
172	        "  setp.ge.s32 p, %5, 0;\n\t"
173	        "  @p ld.L1::no_allocate.L2::cache_hint.global.nc.v4.s32 {%0, %1, %2, %3}, [%4], %6;\n\t"
174	        "}"
175	        : "+r"(ret.x), "+r"(ret.y), "+r"(ret.z), "+r"(ret.w)
176	        : "l"(ptr), "r"(value), "l"(cache_hint)
177	        : "memory");
178	    return ret;
179	}
