239	        return math::advance_ptr<int>(get_topk_weights_ptr(), num_topk * sizeof(float));
240	    }
241	
242	    __forceinline__ __device__ __host__ int* get_linked_list_idx_ptr() const {
243	        return get_src_token_global_idx_ptr() + 1;
244	    }
245	
246	    __forceinline__ __device__ ptx::mbarrier* get_mbarrier_ptr() const {
247	        return math::advance_ptr<ptx::mbarrier>(get_metadata_ptr(), math::align(num_metadata_bytes, ptx::kNumTMAAlignBytes));
248	    }
249	};
250	
251	template <bool kWithMBarrier>
252	struct BufferLayout {
253	    TokenLayout token_layout;
254	    int num_ranks;
255	    int num_max_tokens_per_rank;
256	
257	    void* base;
258	
259	    __forceinline__ __device__ __host__
260	    BufferLayout(const TokenLayout& token_layout,
261	                 const int& num_ranks,
262	                 const int& max_num_tokens_per_rank,
263	                 void* base = nullptr) :
264	        token_layout(token_layout),
265	        num_ranks(num_ranks), num_max_tokens_per_rank(max_num_tokens_per_rank),
266	        base(base) {}
267	
268	    __forceinline__ __device__ __host__
269	    int64_t get_num_bytes_per_token() const {
270	        return token_layout.get_num_bytes<kWithMBarrier, int64_t>();
271	    }
272	
273	    __forceinline__ __device__ __host__
274	    int64_t get_num_bytes_per_rank() const {
275	        return num_max_tokens_per_rank * get_num_bytes_per_token();
276	    }
277	
278	    __forceinline__ __device__ __host__
279	    int64_t get_num_bytes() const {
280	        return get_num_bytes_per_rank() * num_ranks;
281	    }
282	
283	    __forceinline__ __device__ __host__
284	    void* get_buffer_end_ptr() const {
285	        return math::advance_ptr(base, get_num_bytes());
286	    }
287	
288	    __forceinline__ __device__ __host__
289	    BufferLayout get_rank_buffer(const int& rank_idx) const {
290	        return BufferLayout(token_layout,
291	                            1, num_max_tokens_per_rank,
292	                            static_cast<int8_t*>(base) + get_num_bytes_per_rank() * rank_idx);
293	    }
294	
295	    template <int kNumTokensPerChannel>
296	    __forceinline__ __device__ __host__
297	    BufferLayout get_channel_buffer(const int& channel_idx) const {
298	        EP_UNIFIED_ASSERT(num_max_tokens_per_rank % kNumTokensPerChannel == 0);
299	        return BufferLayout(token_layout,
300	                            // Do not use `num_max_tokens_per_rank / kNumTokensPerChannel` as the false stride
301	                            num_ranks, num_max_tokens_per_rank,
302	                            static_cast<int8_t*>(base) + get_num_bytes_per_token() * kNumTokensPerChannel * channel_idx);
303	    }
304	
305	    __forceinline__ __device__ __host__
306	    TokenLayout get_token_buffer(const int& token_idx, const bool& global = false) const {
307	        EP_UNIFIED_ASSERT(num_ranks == 1 or global);
308	        return TokenLayout(token_layout.num_hidden_bytes, token_layout.num_sf_bytes, token_layout.num_topk, token_layout.with_metadata,
309	                           static_cast<int8_t*>(base) + token_layout.get_num_bytes<kWithMBarrier, int64_t>() * token_idx);
310	    }
311	};
